}

function TranscriptionFeed() {
  const [transcripts, setTranscripts] = useState<TranscriptEntry[]>([]);
  const room = useRoomContext();

  useEffect(() => {
    if (!room) return;

    const handleData = (payload: Uint8Array, participant: any) => {
      try {
        const text = new TextDecoder().decode(payload);
        const data = JSON.parse(text);

        if (data.type === "transcription" || data.transcript) {
          const entry: TranscriptEntry = {
            id: `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
            timestamp: new Date().toLocaleTimeString("en-US", { hour12: false }),
            speaker: data.speaker || participant?.identity || "Agent",
            text: data.transcript || data.text || "",
          };
          setTranscripts((prev) => [...prev.slice(-49), entry]);
          telemetry.log("TRANSCRIPTION_RECEIVED", { speaker: entry.speaker });
        }
      } catch {
        // Non-JSON data, ignore
      }
    };

    room.on(RoomEvent.DataReceived, handleData);
    return () => {
      room.off(RoomEvent.DataReceived, handleData);
    };
  }, [room]);

  // Subscribe to participant metadata changes (agent may publish transcriptions there)
  useEffect(() => {
    if (!room) return;

    const handleMetadata = (prevMetadata: string | undefined, participant: any) => {
      try {
        const meta = JSON.parse(participant.metadata || "{}");
        if (meta.lastTranscript) {
          const entry: TranscriptEntry = {
            id: `meta-${Date.now()}`,
            timestamp: new Date().toLocaleTimeString("en-US", { hour12: false }),
            speaker: participant.identity,
            text: meta.lastTranscript,
          };
          setTranscripts((prev) => {
            // Avoid duplicates
            if (prev.some((t) => t.text === entry.text && t.speaker === entry.speaker)) {
              return prev;
            }
            return [...prev.slice(-49), entry];
          });
        }
      } catch {
        // Invalid metadata
      }
    };

    room.on(RoomEvent.ParticipantMetadataChanged, handleMetadata);
    return () => {
      room.off(RoomEvent.ParticipantMetadataChanged, handleMetadata);
    };
  }, [room]);

  if (transcripts.length === 0) {
    return (
      <div className="flex-1 space-y-2 overflow-y-auto">
        <div className="text-blue-400 font-mono text-sm">[SYSTEM] Waiting for transcriptions...</div>
        <div className="text-gray-500 font-mono text-sm opacity-50">
          Monitoring for Ontological Drift...
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 space-y-2 overflow-y-auto font-mono text-sm">
      {transcripts.map((entry) => (
        <div key={entry.id} className="border-l-2 border-gray-700 pl-2 py-1">
          <span className="text-gray-500 text-[10px]">{entry.timestamp}</span>
          <p className="text-white">
            <span className="text-blue-400">{entry.speaker}:</span> {entry.text}
          </p>
        </div>
      ))}
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import {
  Save,
  RotateCcw,
  Server,
  Mic,
  Video,
  Volume2,
  Palette,
  Shield,
  CheckCircle,
  Cpu,
  Download,
  Loader2,
  ExternalLink,
} from "lucide-react";
import { useSettings, getMediaDevices, type AppSettings } from "@/lib/settings";
import Toggle from "@/components/ui/Toggle";
import { cn } from "@/lib/utils";

interface MediaDevices {
  audioInputs: MediaDeviceInfo[];
  videoInputs: MediaDeviceInfo[];
  audioOutputs: MediaDeviceInfo[];
}

export default function SettingsPage() {
  const { settings, isLoaded, updateSettings, resetSettings } = useSettings();
  const [localSettings, setLocalSettings] = useState<AppSettings>(settings);
  const [devices, setDevices] = useState<MediaDevices>({
    audioInputs: [],
    videoInputs: [],
    audioOutputs: [],
  });
  const [isSaved, setIsSaved] = useState(false);
  const [isLoadingDevices, setIsLoadingDevices] = useState(false);

  const [ollamaOk, setOllamaOk] = useState<boolean | null>(null);
  const [ollamaModels, setOllamaModels] = useState<{ name: string }[]>([]);
  const [ollamaLoadingModels, setOllamaLoadingModels] = useState(false);
  const [ollamaPullName, setOllamaPullName] = useState("");
  const [ollamaPulling, setOllamaPulling] = useState(false);
  const [ollamaPullError, setOllamaPullError] = useState<string | null>(null);
  const [ollamaPullProgress, setOllamaPullProgress] = useState<string | null>(null);

  useEffect(() => {
    if (isLoaded) {
      setLocalSettings(settings);
    }
  }, [isLoaded, settings]);

  const loadDevices = async () => {
    setIsLoadingDevices(true);
    try {
      const result = await getMediaDevices();
      setDevices(result);
    } catch (e) {
      console.error("Failed to load devices:", e);
    } finally {
      setIsLoadingDevices(false);
    }
  };

  const checkOllamaStatus = useCallback(async () => {
    try {
      const res = await fetch("/api/ollama/status");
      const data = (await res.json()) as { ok: boolean };
      setOllamaOk(data.ok);
      return data.ok;
    } catch {
      setOllamaOk(false);
      return false;
    }
  }, []);

  const loadOllamaModels = useCallback(async () => {
    setOllamaLoadingModels(true);
    setOllamaPullError(null);
    try {
      const res = await fetch("/api/ollama/models");
      if (!res.ok) {
        setOllamaModels([]);
        return;
      }
      const data = (await res.json()) as { models: { name: string }[] };
      setOllamaModels(data.models ?? []);
    } catch {
      setOllamaModels([]);
    } finally {
      setOllamaLoadingModels(false);
    }
  }, []);

  useEffect(() => {
    checkOllamaStatus().then((ok) => {
      if (ok) loadOllamaModels();
    });
  }, [checkOllamaStatus, loadOllamaModels]);

  const handleOllamaPull = async () => {
    const name = ollamaPullName.trim();
    if (!name) return;
    setOllamaPulling(true);
    setOllamaPullError(null);
    setOllamaPullProgress("Starting...");
    try {
      const res = await fetch("/api/ollama/pull", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: name, stream: true }),
      });
      if (!res.ok || !res.body) {
        const data = (await res.json()) as { error?: string };
        setOllamaPullError(data.error ?? "Pull failed");
        setOllamaPullProgress(null);
        return;
      }
      const reader = res.body.getReader();
      const decoder = new TextDecoder();
      let buf = "";
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buf += decoder.decode(value, { stream: true });
        const lines = buf.split("\n");
        buf = lines.pop() ?? "";
        for (const line of lines) {
          const t = line.trim();
          if (!t) continue;
          try {
            const j = JSON.parse(t) as { status?: string; completed?: number; total?: number };
            const status = j.status ?? "";
            if (j.total != null && j.total > 0 && j.completed != null) {
              const pct = Math.round((j.completed / j.total) * 100);
              setOllamaPullProgress(`${status} ${pct}%`);
            } else {
              setOllamaPullProgress(status || "Downloading...");
            }
          } catch {
            setOllamaPullProgress(t.slice(0, 60));
          }
        }
      }
      setOllamaPullProgress(null);
      await loadOllamaModels();
      setOllamaPullName("");
    } catch (e) {
      setOllamaPullError(e instanceof Error ? e.message : String(e));
      setOllamaPullProgress(null);
    } finally {
      setOllamaPulling(false);
    }
  };

  const handleSave = () => {
    updateSettings(localSettings);
    setIsSaved(true);
    setTimeout(() => setIsSaved(false), 2000);
  };

  const handleReset = () => {
    resetSettings();
    setLocalSettings(settings);
  };

  const updateLocal = (key: keyof AppSettings, value: string | boolean) => {
    setLocalSettings((prev) => ({ ...prev, [key]: value }));
  };

  if (!isLoaded) {
    return (
      <div className="flex items-center justify-center h-full">
        <p className="text-gray-500">Loading settings...</p>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto p-6 space-y-8">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Settings</h1>
          <p className="text-gray-500 text-sm mt-1">
            Configure your AG-Visio experience
          </p>
        </div>
        <div className="flex gap-2">
          <button
            onClick={handleReset}
            className="flex items-center gap-2 px-4 py-2 text-gray-400 hover:text-white hover:bg-neutral-800 rounded-lg transition-colors"
          >
            <RotateCcw className="w-4 h-4" />
            Reset
          </button>
          <button
            onClick={handleSave}
            className={cn(
              "flex items-center gap-2 px-4 py-2 rounded-lg transition-colors",
              isSaved
                ? "bg-green-600 text-white"
                : "bg-blue-600 hover:bg-blue-700 text-white"
            )}
          >
            {isSaved ? (
              <>
                <CheckCircle className="w-4 h-4" />
                Saved
              </>
            ) : (
              <>
                <Save className="w-4 h-4" />
                Save Changes
              </>
            )}
          </button>
        </div>
      </div>

      {/* LiveKit Configuration */}
      <section className="bg-neutral-900 border border-gray-800 rounded-xl p-6">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-blue-600/20 rounded-lg">
            <Server className="w-5 h-5 text-blue-500" />
          </div>
          <div>
            <h2 className="text-lg font-semibold text-white">
              LiveKit Configuration
            </h2>
            <p className="text-gray-500 text-sm">
              Connection settings for the real-time server
            </p>
          </div>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              LiveKit Server URL
            </label>
            <input
              type="text"
              value={localSettings.livekitUrl}
              onChange={(e) => updateLocal("livekitUrl", e.target.value)}
              placeholder="ws://localhost:7880"
              className="w-full px-4 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-blue-500"
            />
            <p className="text-xs text-gray-500 mt-1">
              Override for LiveKit server. When discovery is available, the server
              is auto-detected from your connection (works when joining from
              another device on the same network).
            </p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Default Room Name
            </label>
            <input
              type="text"
              value={localSettings.defaultRoomName}
              onChange={(e) => updateLocal("defaultRoomName", e.target.value)}
              placeholder="ag-visio-conference"
              className="w-full px-4 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-blue-500"
            />
            <p className="text-xs text-gray-500 mt-1">
              Room name used when joining a conference
            </p>
          </div>
        </div>
      </section>

      {/* Ollama (AI agent LLM) */}
      <section className="bg-neutral-900 border border-gray-800 rounded-xl p-6">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-amber-600/20 rounded-lg">
            <Cpu className="w-5 h-5 text-amber-500" />
          </div>
          <div>
            <h2 className="text-lg font-semibold text-white">Ollama (AI Agent)</h2>
            <p className="text-gray-500 text-sm">
              Model discovery, list, and load. Ollama runs outside Docker on your PC.
            </p>
          </div>
        </div>

        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium text-gray-300">Status:</span>
            {ollamaOk === null ? (
              <span className="text-gray-500 text-sm">Checking...</span>
            ) : ollamaOk ? (
              <span className="text-green-500 text-sm flex items-center gap-1">
                <CheckCircle className="w-4 h-4" /> Running
              </span>
            ) : (
              <span className="text-amber-500 text-sm">Not running</span>
            )}
            <button
              type="button"
              onClick={() => {
                checkOllamaStatus().then((ok) => {
                  if (ok) loadOllamaModels();
                });
              }}
              className="ml-2 text-xs text-blue-400 hover:text-blue-300"
            >
              Refresh
            </button>
          </div>

          {!ollamaOk && (
            <div className="rounded-lg bg-amber-900/20 border border-amber-800/50 p-4 text-sm text-amber-200">
              Ollama is not running. Start it on your PC (e.g. <code className="bg-neutral-800 px-1 rounded">ollama serve</code>) or install it.
              <a
                href="https://ollama.com/download"
                target="_blank"
                rel="noopener noreferrer"
                className="ml-2 inline-flex items-center gap-1 text-amber-400 hover:text-amber-300"
              >
                Install Ollama <ExternalLink className="w-3 h-3" />
              </a>
            </div>
          )}

          {ollamaOk && (
            <>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Installed models
                </label>
                <div className="flex items-center gap-2 mb-2">
                  <button
                    type="button"
                    onClick={loadOllamaModels}
                    disabled={ollamaLoadingModels}
                    className="px-3 py-1.5 text-sm bg-neutral-800 hover:bg-neutral-700 text-gray-300 rounded-lg transition-colors disabled:opacity-50"
                  >
                    {ollamaLoadingModels ? "Loading..." : "Refresh list"}
                  </button>
                </div>
                <ul className="list-disc list-inside text-sm text-gray-400 space-y-1 max-h-32 overflow-y-auto">
                  {ollamaModels.length === 0 && !ollamaLoadingModels && (
                    <li className="text-gray-500">No models yet. Load one below.</li>
                  )}
                  {ollamaModels.map((m) => (
                    <li key={m.name} className="font-mono text-gray-300">
                      {m.name}
                    </li>
                  ))}
                </ul>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Load (pull) a model
                </label>
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={ollamaPullName}
                    onChange={(e) => setOllamaPullName(e.target.value)}
                    placeholder="e.g. gemma2, llama3.2"
                    className="flex-1 px-4 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-blue-500"
                  />
                  <button
                    type="button"
                    onClick={handleOllamaPull}
                    disabled={ollamaPulling || !ollamaPullName.trim()}
                    className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:pointer-events-none text-white rounded-lg transition-colors"
                  >
                    {ollamaPulling ? (
                      <Loader2 className="w-4 h-4 animate-spin" />
                    ) : (
                      <Download className="w-4 h-4" />
                    )}
                    Load
                  </button>
                </div>
                {ollamaPullProgress && (
                  <p className="text-sm text-gray-400 mt-2">{ollamaPullProgress}</p>
                )}
                {ollamaPullError && (
                  <p className="text-sm text-red-400 mt-2">{ollamaPullError}</p>
                )}
                <p className="text-xs text-gray-500 mt-2">
                  Agent uses OLLAMA_MODEL (e.g. gemma2); set in agent env or docker-compose.
                </p>
              </div>
            </>
          )}
        </div>
      </section>

      {/* Audio/Video Devices */}
      <section className="bg-neutral-900 border border-gray-800 rounded-xl p-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-green-600/20 rounded-lg">
              <Mic className="w-5 h-5 text-green-500" />
            </div>
            <div>
              <h2 className="text-lg font-semibold text-white">
                Audio & Video Devices
              </h2>
              <p className="text-gray-500 text-sm">
                Select your preferred input/output devices
              </p>
            </div>
          </div>
          <button
            onClick={loadDevices}
            disabled={isLoadingDevices}
            className="px-3 py-1.5 text-sm bg-neutral-800 hover:bg-neutral-700 text-gray-300 rounded-lg transition-colors disabled:opacity-50"
          >
            {isLoadingDevices ? "Loading..." : "Detect Devices"}
          </button>
        </div>

        <div className="space-y-4">
          <div>
            <label className="flex items-center gap-2 text-sm font-medium text-gray-300 mb-2">
              <Mic className="w-4 h-4" />
              Microphone
            </label>
            <select
              value={localSettings.preferredAudioInput}
              onChange={(e) => updateLocal("preferredAudioInput", e.target.value)}
              className="w-full px-4 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:border-blue-500"
            >
              <option value="">System Default</option>
              {devices.audioInputs.map((device) => (
                <option key={device.deviceId} value={device.deviceId}>
                  {device.label || `Microphone ${device.deviceId.slice(0, 8)}`}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="flex items-center gap-2 text-sm font-medium text-gray-300 mb-2">
              <Video className="w-4 h-4" />
              Camera
            </label>
            <select
              value={localSettings.preferredVideoInput}
              onChange={(e) => updateLocal("preferredVideoInput", e.target.value)}
              className="w-full px-4 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:border-blue-500"
            >
              <option value="">System Default</option>
              {devices.videoInputs.map((device) => (
                <option key={device.deviceId} value={device.deviceId}>
                  {device.label || `Camera ${device.deviceId.slice(0, 8)}`}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="flex items-center gap-2 text-sm font-medium text-gray-300 mb-2">
              <Volume2 className="w-4 h-4" />
              Speaker
            </label>
            <select
              value={localSettings.preferredAudioOutput}
              onChange={(e) => updateLocal("preferredAudioOutput", e.target.value)}
              className="w-full px-4 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:border-blue-500"
            >
              <option value="">System Default</option>
              {devices.audioOutputs.map((device) => (
                <option key={device.deviceId} value={device.deviceId}>
                  {device.label || `Speaker ${device.deviceId.slice(0, 8)}`}
                </option>
              ))}
            </select>
          </div>
        </div>

        {devices.audioInputs.length === 0 && (
          <p className="text-xs text-gray-500 mt-4">
            Click "Detect Devices" to load available audio/video devices. You may
            need to grant browser permissions.
          </p>
        )}
      </section>

      {/* Appearance */}
      <section className="bg-neutral-900 border border-gray-800 rounded-xl p-6">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-purple-600/20 rounded-lg">
            <Palette className="w-5 h-5 text-purple-500" />
          </div>
          <div>
            <h2 className="text-lg font-semibold text-white">Appearance</h2>
            <p className="text-gray-500 text-sm">
              Customize the look and feel
            </p>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-300 mb-2">
            Theme
          </label>
          <div className="flex gap-2">
            {(["dark", "light", "system"] as const).map((theme) => (
              <button
                key={theme}
                onClick={() => updateLocal("theme", theme)}
                className={cn(
                  "px-4 py-2 rounded-lg capitalize transition-colors",
                  localSettings.theme === theme
                    ? "bg-blue-600 text-white"
                    : "bg-neutral-800 text-gray-400 hover:text-white"
                )}
              >
                {theme}
              </button>
            ))}
          </div>
          <p className="text-xs text-gray-500 mt-2">
            System uses your OS preference when set to system.
          </p>
        </div>
      </section>

      {/* Privacy */}
      <section className="bg-neutral-900 border border-gray-800 rounded-xl p-6">
        <div className="flex items-center gap-3 mb-6">
          <div className="p-2 bg-orange-600/20 rounded-lg">
            <Shield className="w-5 h-5 text-orange-500" />
          </div>
          <div>
            <h2 className="text-lg font-semibold text-white">Privacy</h2>
            <p className="text-gray-500 text-sm">
              Control data collection and privacy settings
            </p>
          </div>
        </div>

        <div className="space-y-4">
          <Toggle
            checked={localSettings.telemetryEnabled}
            onChange={(checked) => updateLocal("telemetryEnabled", checked)}
            label="Enable Telemetry"
            description="Help improve AG-Visio by sending anonymous usage data"
          />
        </div>
      </section>

      {/* Environment Info */}
      <section className="bg-neutral-800/50 border border-gray-800 rounded-xl p-6">
        <h3 className="text-sm font-medium text-gray-400 mb-3">Environment</h3>
        <div className="grid grid-cols-2 gap-4 text-sm">
          <div>
            <span className="text-gray-500">Version:</span>
            <span className="text-gray-300 ml-2">0.1.0-SOTA</span>
          </div>
          <div>
            <span className="text-gray-500">Environment:</span>
            <span className="text-gray-300 ml-2">
              {process.env.NODE_ENV || "development"}
            </span>
          </div>
          <div>
            <span className="text-gray-500">LiveKit URL:</span>
            <span className="text-gray-300 ml-2 font-mono text-xs">
              {process.env.NEXT_PUBLIC_LIVEKIT_URL || "ws://localhost:7880"}
            </span>
          </div>
        </div>
      </section>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { Video, VideoOff, Mic, MicOff, Volume2, VolumeX, ArrowLeft, CheckCircle2, AlertCircle } from "lucide-react";
import Link from "next/link";
import { cn } from "@/lib/utils";
import { telemetry } from "@/lib/telemetry";

interface DeviceInfo {
  deviceId: string;
  label: string;
  kind: MediaDeviceKind;
}

export default function VideoTestPage() {
  const [videoDevices, setVideoDevices] = useState<DeviceInfo[]>([]);
  const [audioInputDevices, setAudioInputDevices] = useState<DeviceInfo[]>([]);
  const [audioOutputDevices, setAudioOutputDevices] = useState<DeviceInfo[]>([]);
  
  const [selectedVideoDevice, setSelectedVideoDevice] = useState<string>("");
  const [selectedAudioInput, setSelectedAudioInput] = useState<string>("");
  const [selectedAudioOutput, setSelectedAudioOutput] = useState<string>("");
  
  const [isVideoEnabled, setIsVideoEnabled] = useState(true);
  const [isAudioEnabled, setIsAudioEnabled] = useState(true);
  const [isSpeakerEnabled, setIsSpeakerEnabled] = useState(false);
  
  const [mediaStream, setMediaStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [audioLevel, setAudioLevel] = useState(0);
  
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);

  // Load available devices
  useEffect(() => {
    loadDevices();
    telemetry.log("VIDEO_TEST_PAGE_MOUNTED");
    
    return () => {
      cleanupMedia();
      telemetry.log("VIDEO_TEST_PAGE_UNMOUNTED");
    };
  }, []);

  // Start media stream when device selections change
  useEffect(() => {
    if (selectedVideoDevice || selectedAudioInput) {
      startMediaStream();
    }
  }, [selectedVideoDevice, selectedAudioInput, isVideoEnabled, isAudioEnabled]);

  const loadDevices = async () => {
    try {
      // Request permissions first
      await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      
      const devices = await navigator.mediaDevices.enumerateDevices();
      
      const videoDevs = devices.filter(d => d.kind === "videoinput").map(d => ({
        deviceId: d.deviceId,
        label: d.label || `Camera ${d.deviceId.slice(0, 5)}`,
        kind: d.kind,
      }));
      
      const audioInputDevs = devices.filter(d => d.kind === "audioinput").map(d => ({
        deviceId: d.deviceId,
        label: d.label || `Microphone ${d.deviceId.slice(0, 5)}`,
        kind: d.kind,
      }));
      
      const audioOutputDevs = devices.filter(d => d.kind === "audiooutput").map(d => ({
        deviceId: d.deviceId,
        label: d.label || `Speaker ${d.deviceId.slice(0, 5)}`,
        kind: d.kind,
      }));
      
      setVideoDevices(videoDevs);
      setAudioInputDevices(audioInputDevs);
      setAudioOutputDevices(audioOutputDevs);
      
      // Set defaults
      const firstVideo = videoDevs[0];
      if (firstVideo && !selectedVideoDevice) {
        setSelectedVideoDevice(firstVideo.deviceId);
      }
      const firstAudioInput = audioInputDevs[0];
      if (firstAudioInput && !selectedAudioInput) {
        setSelectedAudioInput(firstAudioInput.deviceId);
      }
      const firstAudioOutput = audioOutputDevs[0];
      if (firstAudioOutput && !selectedAudioOutput) {
        setSelectedAudioOutput(firstAudioOutput.deviceId);
      }
      
      telemetry.log("DEVICES_ENUMERATED", {
        video: videoDevs.length,
        audioInput: audioInputDevs.length,
        audioOutput: audioOutputDevs.length,
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Failed to access devices";
      setError(msg);
      telemetry.log("DEVICE_ENUMERATION_FAILED", { error: msg });
    }
  };

  const startMediaStream = async () => {
    try {
      cleanupMedia();
      setError(null);
      
      const constraints: MediaStreamConstraints = {
        video: isVideoEnabled && selectedVideoDevice ? { deviceId: { exact: selectedVideoDevice } } : false,
        audio: isAudioEnabled && selectedAudioInput ? { deviceId: { exact: selectedAudioInput } } : false,
      };
      
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      setMediaStream(stream);
      
      if (videoRef.current && stream.getVideoTracks().length > 0) {
        videoRef.current.srcObject = stream;
      }
      
      // Setup audio level monitoring
      if (stream.getAudioTracks().length > 0) {
        setupAudioMonitoring(stream);
      }
      
      telemetry.log("MEDIA_STREAM_STARTED", {
        video: stream.getVideoTracks().length > 0,
        audio: stream.getAudioTracks().length > 0,
      });
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Failed to start media";
      setError(msg);
      telemetry.log("MEDIA_STREAM_FAILED", { error: msg });
    }
  };

  const setupAudioMonitoring = (stream: MediaStream) => {
    const audioContext = new AudioContext();
    const analyser = audioContext.createAnalyser();
    const microphone = audioContext.createMediaStreamSource(stream);
    
    analyser.fftSize = 256;
    microphone.connect(analyser);
    
    audioContextRef.current = audioContext;
    analyserRef.current = analyser;
    
    monitorAudioLevel();
  };

  const monitorAudioLevel = () => {
    if (!analyserRef.current) return;
    
    const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
    
    const checkLevel = () => {
      if (!analyserRef.current) return;
      
      analyserRef.current.getByteFrequencyData(dataArray);
      const average = dataArray.reduce((a, b) => a + b, 0) / dataArray.length;
      setAudioLevel(Math.min(100, (average / 128) * 100));
      
      animationFrameRef.current = requestAnimationFrame(checkLevel);
    };
    
    checkLevel();
  };

  const cleanupMedia = () => {
    if (mediaStream) {
      mediaStream.getTracks().forEach(track => track.stop());
      setMediaStream(null);
    }
    
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
      animationFrameRef.current = null;
    }
    
    analyserRef.current = null;
    setAudioLevel(0);
  };

  const toggleVideo = () => {
    if (mediaStream) {
      const videoTrack = mediaStream.getVideoTracks()[0];
      if (videoTrack) {
        videoTrack.enabled = !videoTrack.enabled;
        setIsVideoEnabled(videoTrack.enabled);
      }
    } else {
      setIsVideoEnabled(!isVideoEnabled);
    }
  };

  const toggleAudio = () => {
    if (mediaStream) {
      const audioTrack = mediaStream.getAudioTracks()[0];
      if (audioTrack) {
        audioTrack.enabled = !audioTrack.enabled;
        setIsAudioEnabled(audioTrack.enabled);
      }
    } else {
      setIsAudioEnabled(!isAudioEnabled);
    }
  };

  const playTestSound = () => {
    const audio = new Audio("/test-tone.mp3");
    
    if ("setSinkId" in audio && selectedAudioOutput) {
      (audio as any).setSinkId(selectedAudioOutput).catch((err: Error) => {
        telemetry.log("AUDIO_OUTPUT_FAILED", { error: err.message });
      });
    }
    
    audio.play();
    setIsSpeakerEnabled(true);
    setTimeout(() => setIsSpeakerEnabled(false), 1000);
  };

  const hasVideo = mediaStream?.getVideoTracks().length ?? 0 > 0;
  const hasAudio = mediaStream?.getAudioTracks().length ?? 0 > 0;

  return (
    <div className="flex h-screen flex-col bg-neutral-950">
      {/* Header */}
      <header className="flex items-center justify-between px-6 py-4 border-b border-gray-800">
        <div className="flex items-center gap-4">
          <Link
            href="/"
            className="flex items-center gap-2 text-gray-400 hover:text-white transition-colors"
          >
            <ArrowLeft className="w-4 h-4" />
            Back to Dashboard
          </Link>
          <div className="h-4 w-px bg-gray-700" />
          <h1 className="text-lg font-semibold text-white">Video & Audio Test</h1>
        </div>
      </header>

      <div className="flex-1 flex items-center justify-center p-8">
        <div className="w-full max-w-4xl space-y-6">
          {/* Video Preview */}
          <div className="relative bg-neutral-900 rounded-xl overflow-hidden border border-gray-800">
            <div className="aspect-video relative bg-black">
              {isVideoEnabled && hasVideo ? (
                <video
                  ref={videoRef}
                  autoPlay
                  playsInline
                  muted
                  className="w-full h-full object-cover mirror"
                />
              ) : (
                <div className="flex items-center justify-center h-full">
                  <div className="text-center">
                    <VideoOff className="w-16 h-16 text-gray-600 mx-auto mb-3" />
                    <p className="text-gray-500">Camera is off</p>
                  </div>
                </div>
              )}
              
              {/* Status Indicators */}
              <div className="absolute top-4 left-4 flex gap-2">
                <div className={cn(
                  "flex items-center gap-2 px-3 py-1.5 rounded-lg backdrop-blur-sm",
                  hasVideo ? "bg-green-900/50 text-green-400" : "bg-red-900/50 text-red-400"
                )}>
                  {hasVideo ? <CheckCircle2 className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
                  <span className="text-xs font-medium">Video</span>
                </div>
                
                <div className={cn(
                  "flex items-center gap-2 px-3 py-1.5 rounded-lg backdrop-blur-sm",
                  hasAudio ? "bg-green-900/50 text-green-400" : "bg-red-900/50 text-red-400"
                )}>
                  {hasAudio ? <CheckCircle2 className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
                  <span className="text-xs font-medium">Audio</span>
                </div>
              </div>
            </div>

            {/* Controls */}
            <div className="p-4 flex items-center justify-center gap-4">
              <button
                onClick={toggleVideo}
                className={cn(
                  "p-4 rounded-full transition-colors",
                  isVideoEnabled
                    ? "bg-neutral-700 hover:bg-neutral-600 text-white"
                    : "bg-red-600 hover:bg-red-700 text-white"
                )}
                title={isVideoEnabled ? "Turn off camera" : "Turn on camera"}
              >
                {isVideoEnabled ? <Video className="w-5 h-5" /> : <VideoOff className="w-5 h-5" />}
              </button>

              <button
                onClick={toggleAudio}
                className={cn(
                  "p-4 rounded-full transition-colors",
                  isAudioEnabled
                    ? "bg-neutral-700 hover:bg-neutral-600 text-white"
                    : "bg-red-600 hover:bg-red-700 text-white"
                )}
                title={isAudioEnabled ? "Mute microphone" : "Unmute microphone"}
              >
                {isAudioEnabled ? <Mic className="w-5 h-5" /> : <MicOff className="w-5 h-5" />}
              </button>
            </div>
          </div>

          {/* Audio Level Indicator */}
          {hasAudio && (
            <div className="bg-neutral-900 rounded-xl p-4 border border-gray-800">
              <div className="flex items-center gap-3">
                <Mic className="w-4 h-4 text-gray-500" />
                <div className="flex-1">
                  <div className="h-2 bg-neutral-800 rounded-full overflow-hidden">
                    <div
                      className={cn(
                        "h-full transition-all duration-100",
                        audioLevel > 70 ? "bg-red-500" : audioLevel > 40 ? "bg-yellow-500" : "bg-green-500"
                      )}
                      style={{ width: `${audioLevel}%` }}
                    />
                  </div>
                </div>
                <span className="text-xs text-gray-500 w-12 text-right">
                  {Math.round(audioLevel)}%
                </span>
              </div>
              <p className="text-xs text-gray-500 mt-2">
                Speak to test your microphone
              </p>
            </div>
          )}

          {/* Device Selection */}
          <div className="grid md:grid-cols-3 gap-4">
            {/* Camera */}
            <div className="bg-neutral-900 rounded-xl p-4 border border-gray-800">
              <label className="block text-sm font-medium text-gray-400 mb-2">
                Camera
              </label>
              <select
                value={selectedVideoDevice}
                onChange={(e) => setSelectedVideoDevice(e.target.value)}
                className="w-full px-3 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white text-sm focus:outline-none focus:border-blue-500"
              >
                {videoDevices.map(device => (
                  <option key={device.deviceId} value={device.deviceId}>
                    {device.label}
                  </option>
                ))}
              </select>
            </div>

            {/* Microphone */}
            <div className="bg-neutral-900 rounded-xl p-4 border border-gray-800">
              <label className="block text-sm font-medium text-gray-400 mb-2">
                Microphone
              </label>
              <select
                value={selectedAudioInput}
                onChange={(e) => setSelectedAudioInput(e.target.value)}
                className="w-full px-3 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white text-sm focus:outline-none focus:border-blue-500"
              >
                {audioInputDevices.map(device => (
                  <option key={device.deviceId} value={device.deviceId}>
                    {device.label}
                  </option>
                ))}
              </select>
            </div>

            {/* Speakers */}
            <div className="bg-neutral-900 rounded-xl p-4 border border-gray-800">
              <label className="block text-sm font-medium text-gray-400 mb-2">
                Speakers
              </label>
              <select
                value={selectedAudioOutput}
                onChange={(e) => setSelectedAudioOutput(e.target.value)}
                className="w-full px-3 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-white text-sm focus:outline-none focus:border-blue-500 mb-2"
              >
                {audioOutputDevices.map(device => (
                  <option key={device.deviceId} value={device.deviceId}>
                    {device.label}
                  </option>
                ))}
              </select>
              <button
                onClick={playTestSound}
                className="w-full px-3 py-1.5 bg-neutral-700 hover:bg-neutral-600 rounded text-sm transition-colors flex items-center justify-center gap-2"
              >
                {isSpeakerEnabled ? <VolumeX className="w-4 h-4" /> : <Volume2 className="w-4 h-4" />}
                Test Speaker
              </button>
            </div>
          </div>

          {/* Error Display */}
          {error && (
            <div className="bg-red-900/30 border border-red-800 rounded-xl p-4">
              <div className="flex items-start gap-3">
                <AlertCircle className="w-5 h-5 text-red-400 flex-shrink-0 mt-0.5" />
                <div>
                  <p className="text-red-400 font-medium">Error</p>
                  <p className="text-red-300 text-sm mt-1">{error}</p>
                </div>
              </div>
            </div>
          )}

          {/* Ready to Join */}
          {hasVideo && hasAudio && !error && (
            <div className="bg-green-900/20 border border-green-800 rounded-xl p-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <CheckCircle2 className="w-5 h-5 text-green-400" />
                  <div>
                    <p className="text-green-400 font-medium">Ready to join</p>
                    <p className="text-green-300/70 text-sm">Your camera and microphone are working</p>
                  </div>
                </div>
                <Link
                  href="/"
                  className="px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors font-medium"
                >
                  Join Conference
                </Link>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useRef } from "react";
import Modal from "@/components/ui/Modal";
import { Terminal, Download, Trash2, Filter } from "lucide-react";
import { telemetry } from "@/lib/telemetry";
import { cn } from "@/lib/utils";

interface LogViewerProps {
  isOpen: boolean;
  onClose: () => void;
}

interface LogEntry {
  id: string;
  timestamp: string;
  level: "info" | "warning" | "error" | "success";
  event: string;
  metadata?: any;
}

const levelColors = {
  info: "text-blue-400 bg-blue-900/30",
  warning: "text-yellow-400 bg-yellow-900/30",
  error: "text-red-400 bg-red-900/30",
  success: "text-green-400 bg-green-900/30",
};

const levelLabels = {
  info: "INFO",
  warning: "WARN",
  error: "ERROR",
  success: "OK",
};

export default function LogViewer({ isOpen, onClose }: LogViewerProps) {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [filter, setFilter] = useState<"all" | "info" | "warning" | "error" | "success">("all");
  const [autoScroll, setAutoScroll] = useState(true);
  const logContainerRef = useRef<HTMLDivElement>(null);

  // Intercept telemetry logs
  useEffect(() => {
    if (!isOpen) return;

    const originalLog = telemetry.log;
    const originalError = telemetry.error;

    telemetry.log = (event: string, metadata?: any) => {
      originalLog(event, metadata);
      addLog("info", event, metadata);
    };

    telemetry.error = (message: string, error?: any) => {
      originalError(message, error);
      addLog("error", message, { error });
    };

    // Intercept console.log as well
    const originalConsoleLog = console.log;
    const originalConsoleWarn = console.warn;
    const originalConsoleError = console.error;

    console.log = (...args: any[]) => {
      originalConsoleLog(...args);
      addLog("info", args.join(" "));
    };

    console.warn = (...args: any[]) => {
      originalConsoleWarn(...args);
      addLog("warning", args.join(" "));
    };

    console.error = (...args: any[]) => {
      originalConsoleError(...args);
      addLog("error", args.join(" "));
    };

    return () => {
      telemetry.log = originalLog;
      telemetry.error = originalError;
      console.log = originalConsoleLog;
      console.warn = originalConsoleWarn;
      console.error = originalConsoleError;
    };
  }, [isOpen]);

  const addLog = (
    level: "info" | "warning" | "error" | "success",
    event: string,
    metadata?: any
  ) => {
    const entry: LogEntry = {
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
      timestamp: new Date().toISOString(),
      level,
      event,
      metadata,
    };

    setLogs((prev) => [...prev.slice(-999), entry]);
  };

  // Auto-scroll to bottom
  useEffect(() => {
    if (autoScroll && logContainerRef.current) {
      logContainerRef.current.scrollTop = logContainerRef.current.scrollHeight;
    }
  }, [logs, autoScroll]);

  const filteredLogs = logs.filter(
    (log) => filter === "all" || log.level === filter
  );

  const downloadLogs = () => {
    const content = filteredLogs
      .map(
        (log) =>
          `[${log.timestamp}] ${levelLabels[log.level]}: ${log.event}${
            log.metadata ? ` | ${JSON.stringify(log.metadata)}` : ""
          }`
      )
      .join("\n");

    const blob = new Blob([content], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `ag-visio-logs-${Date.now()}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const clearLogs = () => {
    setLogs([]);
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Log Viewer"
      size="xl"
    >
      <div className="flex flex-col h-[600px]">
        {/* Toolbar */}
        <div className="flex items-center justify-between px-6 py-3 border-b border-gray-800">
          <div className="flex items-center gap-2">
            <Terminal className="w-4 h-4 text-gray-500" />
            <span className="text-sm text-gray-400">
              {filteredLogs.length} {filteredLogs.length === 1 ? "entry" : "entries"}
            </span>
          </div>

          <div className="flex items-center gap-2">
            {/* Filter */}
            <div className="flex items-center gap-1 bg-neutral-800 rounded-lg p-1">
              <Filter className="w-3 h-3 text-gray-500 ml-2" />
              {(["all", "info", "warning", "error", "success"] as const).map((f) => (
                <button
                  key={f}
                  onClick={() => setFilter(f)}
                  className={cn(
                    "px-2 py-1 text-xs rounded transition-colors capitalize",
                    filter === f
                      ? "bg-blue-600 text-white"
                      : "text-gray-400 hover:text-white"
                  )}
                >
                  {f}
                </button>
              ))}
            </div>

            {/* Auto-scroll Toggle */}
            <label className="flex items-center gap-2 text-xs text-gray-400 cursor-pointer">
              <input
                type="checkbox"
                checked={autoScroll}
                onChange={(e) => setAutoScroll(e.target.checked)}
                className="rounded"
              />
              Auto-scroll
            </label>

            {/* Download */}
            <button
              onClick={downloadLogs}
              className="p-1.5 text-gray-400 hover:text-white hover:bg-neutral-700 rounded transition-colors"
              title="Download logs"
            >
              <Download className="w-4 h-4" />
            </button>

            {/* Clear */}
            <button
              onClick={clearLogs}
              className="p-1.5 text-gray-400 hover:text-red-400 hover:bg-neutral-700 rounded transition-colors"
              title="Clear logs"
            >
              <Trash2 className="w-4 h-4" />
            </button>
          </div>
        </div>

        {/* Log Entries */}
        <div
          ref={logContainerRef}
          className="flex-1 overflow-y-auto px-6 py-4 bg-black/30 font-mono text-xs"
        >
          {filteredLogs.length === 0 ? (
            <div className="flex items-center justify-center h-full text-gray-600">
              No logs to display
            </div>
          ) : (
            <div className="space-y-1">
              {filteredLogs.map((log) => (
                <div
                  key={log.id}
                  className="flex items-start gap-3 py-1 hover:bg-neutral-900/50 rounded px-2"
                >
                  <span className="text-gray-600 flex-shrink-0 w-24">
                    {new Date(log.timestamp).toLocaleTimeString("en-US", {
                      hour12: false,
                      hour: "2-digit",
                      minute: "2-digit",
                      second: "2-digit",
                    })}
                  </span>
                  <span
                    className={cn(
                      "px-1.5 py-0.5 rounded text-[10px] font-semibold flex-shrink-0",
                      levelColors[log.level]
                    )}
                  >
                    {levelLabels[log.level]}
                  </span>
                  <span className="text-gray-300 flex-1">{log.event}</span>
                  {log.metadata && (
                    <span className="text-gray-600 text-[10px]">
                      {JSON.stringify(log.metadata)}
                    </span>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </Modal>
  );
}

"use client";

import { useState, useEffect } from "react";
import Modal from "@/components/ui/Modal";

interface ShareRoomModalProps {
  isOpen: boolean;
  onClose: () => void;
  roomName: string;
}

export default function ShareRoomModal({
  isOpen,
  onClose,
  roomName,
}: ShareRoomModalProps) {
  const [copied, setCopied] = useState(false);
  const roomUrl =
    typeof window !== "undefined"
      ? `${window.location.origin}?room=${encodeURIComponent(roomName)}`
      : "";

  const qrUrl = roomUrl
    ? `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(roomUrl)}`
    : "";

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(roomUrl);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      setCopied(false);
    }
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Join ${roomName}`,
          text: `Join the conference room: ${roomName}`,
          url: roomUrl,
        });
        onClose();
      } catch (e) {
        if ((e as Error).name !== "AbortError") {
          handleCopy();
        }
      }
    } else {
      handleCopy();
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Share Room Link">
      <div className="flex flex-col items-center gap-4 p-4">
        {qrUrl && (
          <img
            src={qrUrl}
            alt="QR code for room"
            className="w-48 h-48 rounded-lg bg-white p-2"
          />
        )}
        <div className="w-full">
          <label className="block text-xs text-gray-500 mb-1">Room URL</label>
          <div className="flex gap-2">
            <input
              type="text"
              readOnly
              value={roomUrl}
              className="flex-1 px-3 py-2 bg-neutral-800 border border-gray-700 rounded-lg text-sm text-gray-300"
            />
            <button
              onClick={handleCopy}
              className="px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg text-sm font-medium whitespace-nowrap"
            >
              {copied ? "Copied" : "Copy"}
            </button>
          </div>
        </div>
        <button
          onClick={handleShare}
          className="w-full px-4 py-2 bg-neutral-700 hover:bg-neutral-600 rounded-lg text-sm"
        >
          Share via...
        </button>
      </div>
    </Modal>
  );
}

export const telemetry = {
    log: (event: string, metadata?: any) => {
        const timestamp = new Date().toISOString();
        const payload = {
            timestamp,
            event,
            ...metadata,
            context: "AG-Visio-SOTA-Web"
        };
        console.log(`[SOTA-TELEMETRY] ${JSON.stringify(payload)}`);
        // In a production scenario, this would POST to a logging sink
    },
    error: (message: string, error?: any) => {
        telemetry.log("ERROR", { message, error: error?.message || error });
    }
};

